import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{a as i,i as a,n as o,o as s,r as c,s as l,t as u}from"./chunks/javap.CpTN0-Ru.js";const d=JSON.parse(`{"title":"Поради та підказки VS Code","description":"Корисні поради та підказки, які полегшать вашу роботу.","frontmatter":{"title":"Поради та підказки VS Code","description":"Корисні поради та підказки, які полегшать вашу роботу.","authors":["dicedpixels"],"prev":{"text":"Генерація джерел у VS Code","link":"./generating-sources"},"next":false,"files":[]},"headers":[],"relativePath":"uk_ua/develop/getting-started/vscode/tips-and-tricks.md","filePath":"translated/uk_ua/develop/getting-started/vscode/tips-and-tricks.md","lastUpdated":1774518827000}`);var f={name:`uk_ua/develop/getting-started/vscode/tips-and-tricks.md`};function p(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Поради та підказки VS Code <a class="header-anchor" href="#h1" aria-label="Permalink to “Поради та підказки VS Code”">​</a></h1><p>Важливо навчитися проходити генеровані джерела, щоб ви могли налагодити та отримати розуміння внутрішньої роботи Minecraft. Тут ми описуємо деякі загальні використання IDE.</p><h2 id="searching-for-a-minecraft-class" tabindex="-1">Пошук класів Minecraft <a class="header-anchor" href="#searching-for-a-minecraft-class" aria-label="Permalink to “Пошук класів Minecraft”">​</a></h2><p>Коли джерела будуть згенеровані, ви зможете шукати або переглядати класи Minecraft.</p><h3 id="viewing-class-definitions" tabindex="-1">Перегляд визначень класів <a class="header-anchor" href="#viewing-class-definitions" aria-label="Permalink to “Перегляд визначень класів”">​</a></h3><p><strong>Швидке відкриття</strong> (<kbd>Ctrl</kbd>+<kbd>P</kbd>): введіть <code>#</code>, а потім назву класу (наприклад, <code>#Identifier</code>).</p><p><img src="/assets/develop/getting-started/vscode/quick-open.png" alt="Швидке відриття" loading="lazy"></p><p><strong>Go to Definition</strong> (<kbd>F12</kbd>): у вихідному коді перейдіть до визначення класу, натиснувши <kbd>Ctrl</kbd> і натиснувши його назву, або натиснувши по ньому ПКМ та вибравши «Go to Definition».</p><p><img src="/assets/develop/getting-started/vscode/go-to-definition.png" alt="Go to Definition" loading="lazy"></p><h3 id="finding-references" tabindex="-1">Пошук посилань <a class="header-anchor" href="#finding-references" aria-label="Permalink to “Пошук посилань”">​</a></h3><p>Ви можете знайти всі використання класу, Натиснувши ПКМ по назві класу та вибравши <strong>Find All References</strong>.</p><p><img src="/assets/develop/getting-started/vscode/find-all-references.png" alt="Find All References" loading="lazy"></p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Якщо наведені вище функції не працюють належним чином, ймовірно, джерела не приєднані належним чином. Зазвичай це можна виправити, очистивши кеш робочої області.</p><ul><li>Натисніть кнопку <strong>Show Java Status Menu</strong> у рядку стану.</li></ul><p><img src="/assets/develop/getting-started/vscode/java-ready.png" alt="Показати стан Java" loading="lazy"></p><ul><li>У щойно відкритому меню натисніть <strong>Clean Workspace Cache…</strong> і підтвердьте операцію.</li></ul><p><img src="/assets/develop/getting-started/vscode/clear-workspace.png" alt="Очистити робочій простір" loading="lazy"></p><ul><li>Закрийте та заново відкрийте проєкт.</li></ul></div><h2 id="viewing-bytecode" tabindex="-1">Перегляд байт-коду <a class="header-anchor" href="#viewing-bytecode" aria-label="Permalink to “Перегляд байт-коду”">​</a></h2><p>Перегляд байт-коду необхідний під час написання міксинів. Однак Visual Studio Code не має вбудованої підтримки для перегляду байт-коду, і кілька розширень, які його додають, можуть не працювати.</p><p>У такому випадку ви можете використовувати вбудований Javap <code>javap</code> для перегляду байт-коду.</p><ul><li><p><strong>Знайдіть шлях до Minecraft JAR:</strong></p><p>Відкрийте вікно провідника, розгорніть розділ <strong>Java Projects</strong>. Розгорніть нод <strong>Reference Libraries</strong> в дереві проєкту та знайдіть файл JAR із <code>minecraft-</code> у його імені. Натисніть ПКМ по JAR і скопіюйте повний шлях.</p><p>Це може виглядати приблизно так:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>C:/project/.gradle/loom-cache/minecraftMaven/net/minecraft/minecraft-merged-503b555a3d/1.21.8-net.fabricmc.yarn.1_21_8.1.21.8+build.1-v2/minecraft-merged-503b555a3d-1.21.8-net.fabricmc.yarn.1_21_8.1.21.8+build.1-v2.jar</span></span></code></pre></div></li></ul><p><img src="/assets/develop/getting-started/vscode/copy-path.png" alt="Копіювати шлях" loading="lazy"></p><ul><li><p><strong>Запустіть <code>javap</code>:</strong></p><p>Потім ви можете запустити <code>javap</code>, вказавши вищевказаний шлях як <code>cp</code> (шлях до класу) і повну назву класу як останній аргумент.</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">javap</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> C:/project/.gradle/loom-cache/minecraftMaven/net/minecraft/minecraft-merged-503b555a3d/1.21.8-net.fabricmc.yarn.1_21_8.1.21.8+build.1-v2/minecraft-merged-503b555a3d-1.21.8-net.fabricmc.yarn.1_21_8.1.21.8+build.1-v2.jar</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -private</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> net.minecraft.util.Identifier</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Це виведе байт-код у вивід вашого термінала.</p></li></ul><p><img src="/assets/develop/getting-started/vscode/javap.png" alt="javap" loading="lazy"></p>`,20)]])}var m=r(f,[[`render`,p]]);export{d as __pageData,m as default};